/**
 * Module application, used to define a module application.
 */
Cls['Wb.App'] = class app extends Wb.Base {
  /**
   * The main method executed after the module is initialized, returning the application's main component.
   * @param {Wb.Container} ct The container component. The module's main component will be added to this container.
   * @return {Wb.Component} The main component. If a component is returned, the system will automatically add it to
   * the container.
   * @function main
   */
  /** @property {Object} configs Configuration parameters. */
  /**
   * @event ready Fired after the object initialization is complete.
   * @param {Object} configs The configuration parameters.
   */
  /**
   * Method executed when the constructor finishes. Can be overridden to perform operations related to post-initialization.
   * @param {Object} configs The configuration parameters.
   * @priv
   * @function ready
   */
  /** @property {Wb.Component} mainCt The main component returned within the `main` method. Typically added to the context
   * container. */
  /**
   * Constructor method.
   * @param {Wb.Container/Boolean} [container] The container to which the application's main component will be added. If
   * `false`, it is not added; if omitted, the main component will be rendered to {#globalThis.BodyEl}.
   * @param {Object} [configs] Configuration parameters. Will be directly set to the {#configs} property.
   */
  constructor(container, configs) {
    let mainCt;

    super();
    this.configs = configs;
    mainCt = this.mainCt = this.main?.(container);
    if (mainCt && container !== false) {
      if (container)
        container.add(mainCt);
      else if (!mainCt.el.isConnected)
        BodyEl.insertBefore(mainCt.el, BodyEl.firstChild);
    }
    this.ready?.(configs);
    this.fireEvent('ready', configs);
  }
}
