/**
 * Used to define a module. A module is a closure with an independent namespace. Server-side scripting can be performed within
 * the {#serverScript} property of the module; these scripts are executed when the module is invoked. {#initialize} is the
 * client-side initialization event; besides handling client-side initialization, it can also define public methods and
 * properties within the client-side module.
 * @icon module
 */
Cls['Wb.Module'] = class module {
  /** @property {TextString} description A detailed description of the module. */
  /** @property {String} remark A remark about the module. */
  /** @property {Enum} moduleType The client-side target type for the module:
   * -'desktop': Targeted at desktops.
   * -'touch': Targeted at mobile touch devices.
   * -'any': Adapts to any type. Default value.
   */
  /** @property {Function} serverScript The script executed on the server side. The system automatically runs this script on
   * the server when requesting or running the module. @key */
  /** @property {String} serverMethod The Java static method(request, response) executed on the server side. After running
   * the `serverScript`, the system automatically runs this method on the server. */
  /** @property {String} title The module title. */
  /** @property {Boolean/String} theme Specifies the UI theme name to use. `true` represents "classic", `false` represents
   * "dark". */
  /** @property {String} cid The module identifier. @key */
  /** @property {String} cls Space-separated CSS class names added to the {#globalThis.BodyEl} in the window. */
  /** @property {String} style Semicolon-separated CSS styles added to the {#globalThis.BodyEl} in the window. */
  /** @property {String} bodyTag Arbitrary script added to the {#globalThis.BodyEl} in the window. */
  /** @property {String[]} links A list of JS/CSS resource links to be loaded before the module runs. @key */
  /** @property {Boolean} loginRequired Whether login and permission check are required before accessing the module. @key */
  /** @property {String} language The language to use. Defaults to the system setting. */
  /** @property {Boolean} obfuscate Whether to obfuscate and encrypt the code when minifying files. */
  /** @property {HtmlString} head Header information output to the page's `<head>` node. */
  /**
   * @event beforeunload Fired before the module closes. Returning `false` prevents the closure.
   */
  /**
   * @event initialize Custom client-side script executed before the module loads. Public methods and properties within the
   * module can be defined here. @key
   */
  /**
   * @event finalize Custom client-side script executed after the module loads.
   */
}
